		if(strlen($s_dir)>65) $s_dir=substr($s_dir,0,62)."...";
		$s_item=str_ireplace($GLOBALS['home_dir'], '', $item );	if(strlen($s_item)>45) $s_item=substr($s_item,0,42)."...";
